import React, { useState, useEffect, useRef } from 'react';
import { 
  Container, 
  Box, 
  Paper, 
  Typography, 
  TextField, 
  Button, 
  IconButton,
  Grid,
  Chip,
  CircularProgress,
  Card,
  CardContent,
  FormControl,
  RadioGroup,
  FormControlLabel,
  Radio,
  Snackbar,
  Alert,
  Divider
} from '@mui/material';
import { 
  Send, 
  Psychology,
  AccountBalanceWallet,
  CurrencyExchange,
  Add
} from '@mui/icons-material';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

const NaturalLanguage = () => {
  const { currentUser } = useAuth();
  const [query, setQuery] = useState('');
  const [conversations, setConversations] = useState([]);
  const [currentConversation, setCurrentConversation] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [agentType, setAgentType] = useState('payment');
  const [error, setError] = useState(null);
  const messagesEndRef = useRef(null);
  const [loadingConversations, setLoadingConversations] = useState(true);

  // Fetch conversations on component mount
  useEffect(() => {
    fetchConversations();
  }, []);

  // Scroll to bottom whenever messages change
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Fetch messages when conversation changes
  useEffect(() => {
    if (currentConversation) {
      fetchMessages(currentConversation);
    }
  }, [currentConversation]);

  const fetchConversations = async () => {
    setLoadingConversations(true);
    try {
      const response = await axios.get('/ai/conversations/');
      setConversations(response.data);

      // If there are conversations, select the most recent one
      if (response.data.length > 0) {
        setCurrentConversation(response.data[0].id);
      }
    } catch (err) {
      console.error('Error fetching conversations:', err);
      setError('Failed to load conversations');
    } finally {
      setLoadingConversations(false);
    }
  };

  const fetchMessages = async (conversationId) => {
    setLoading(true);
    try {
      const response = await axios.get(`/ai/conversations/${conversationId}/`);
      setMessages(response.data.messages || []);
    } catch (err) {
      console.error('Error fetching messages:', err);
      setError('Failed to load messages');
    } finally {
      setLoading(false);
    }
  };

  const handleStartNewConversation = () => {
    setCurrentConversation(null);
    setMessages([]);
  };

  const handleSendMessage = async () => {
    if (!query.trim()) return;

    // Add user message to UI immediately
    const userMessage = {
      id: Date.now(),
      role: 'user',
      content: query,
      timestamp: new Date().toISOString()
    };

    setMessages(prev => [...prev, userMessage]);

    // Clear the input
    setQuery('');

    // Set loading state
    setLoading(true);
    setError(null);

    try {
      const requestData = {
        query: query,
        agent_type: agentType,
      };

      // If we're continuing a conversation, include the conversation ID
      let response;
      if (currentConversation) {
        response = await axios.post(`/ai/conversations/${currentConversation}/messages/`, requestData);
      } else {
        response = await axios.post('/ai/process/', requestData);
        // Update the current conversation with the new one
        setCurrentConversation(response.data.conversation_id);
        // Also update the conversations list
        fetchConversations();
      }

      // Add AI response to messages
      const aiMessage = {
        id: response.data.id || Date.now() + 1,
        role: 'assistant',
        content: response.data.message || response.data.response,
        timestamp: new Date().toISOString()
      };

      setMessages(prev => [...prev, aiMessage]);
    } catch (err) {
      console.error('Error sending message:', err);
      setError(err.response?.data?.detail || 'Failed to process your request');
    } finally {
      setLoading(false);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const formatTimestamp = (timestamp) => {
    const date = new Date(timestamp);
    return new Intl.DateTimeFormat('en-US', {
      hour: '2-digit',
      minute: '2-digit'
    }).format(date);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const getSuggestions = () => {
    if (agentType === 'payment') {
      return [
        "Send $50 to Alex",
        "What's my balance in all wallets?",
        "Convert 100 USD to EUR",
        "How much did I spend last month?"
      ];
    } else {
      return [
        "Show me my transaction history",
        "What are my spending trends?",
        "Generate a report of my finances",
        "Analyze my spending categories"
      ];
    }
  };

  const handleSuggestionClick = (suggestion) => {
    setQuery(suggestion);
  };

  return (
    <Container maxWidth="lg">
      <Grid container spacing={3}>
        {/* Left sidebar - conversation list */}
        <Grid item xs={12} md={3}>
          <Paper sx={{ p: 2, height: 'calc(100vh - 140px)', display: 'flex', flexDirection: 'column' }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
              <Typography variant="h6">Conversations</Typography>
              <IconButton 
                color="primary" 
                onClick={handleStartNewConversation}
                title="New Conversation"
              >
                <Add />
              </IconButton>
            </Box>
            <Divider sx={{ mb: 2 }} />

            {loadingConversations ? (
              <Box display="flex" justifyContent="center" mt={3}>
                <CircularProgress size={30} />
              </Box>
            ) : conversations.length === 0 ? (
              <Box textAlign="center" mt={3}>
                <Typography variant="body2" color="text.secondary">
                  No conversations yet
                </Typography>
              </Box>
            ) : (
              <Box sx={{ overflowY: 'auto', flexGrow: 1 }}>
                {conversations.map((conversation) => (
                  <Card 
                    key={conversation.id} 
                    sx={{ 
                      mb: 1, 
                      cursor: 'pointer',
                      bgcolor: currentConversation === conversation.id ? 'action.selected' : 'background.paper'
                    }}
                    onClick={() => setCurrentConversation(conversation.id)}
                  >
                    <CardContent sx={{ p: 2, '&:last-child': { pb: 2 } }}>
                      <Typography variant="subtitle2" noWrap>
                        {conversation.title || 'Conversation ' + conversation.id.substring(0, 8)}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        {new Date(conversation.created_at).toLocaleDateString()}
                      </Typography>
                    </CardContent>
                  </Card>
                ))}
              </Box>
            )}
          </Paper>
        </Grid>

        {/* Main chat area */}
        <Grid item xs={12} md={9}>
          <Paper sx={{ p: 0, height: 'calc(100vh - 140px)', display: 'flex', flexDirection: 'column' }}>
            {/* Agent type selection */}
            <Box sx={{ p: 2, borderBottom: 1, borderColor: 'divider' }}>
              <FormControl component="fieldset">
                <RadioGroup
                  row
                  name="agent-type"
                  value={agentType}
                  onChange={(e) => setAgentType(e.target.value)}
                >
                  <FormControlLabel 
                    value="payment" 
                    control={<Radio />} 
                    label={
                      <Box display="flex" alignItems="center">
                        <CurrencyExchange sx={{ mr: 1 }} />
                        <Typography>Payment</Typography>
                      </Box>
                    } 
                  />
                  <FormControlLabel 
                    value="data" 
                    control={<Radio />} 
                    label={
                      <Box display="flex" alignItems="center">
                        <Assessment sx={{ mr: 1 }} />
                        <Typography>Data & Analytics</Typography>
                      </Box>
                    } 
                  />
                </RadioGroup>
              </FormControl>
            </Box>

            {/* Messages area */}
            <Box sx={{ p: 3, flexGrow: 1, overflowY: 'auto' }}>
              {messages.length === 0 ? (
                <Box 
                  display="flex" 
                  flexDirection="column" 
                  alignItems="center" 
                  justifyContent="center" 
                  height="100%"
                >
                  <Psychology sx={{ fontSize: 80, color: 'primary.main', opacity: 0.7, mb: 2 }} />
                  <Typography variant="h5" gutterBottom>
                    How can I assist you today?
                  </Typography>
                  <Typography variant="body1" color="text.secondary" align="center" sx={{ maxWidth: 450, mb: 4 }}>
                    Ask me anything about your finances, send money, or get insights about your spending.
                  </Typography>

                  <Grid container spacing={1} justifyContent="center" sx={{ maxWidth: 600 }}>
                    {getSuggestions().map((suggestion, index) => (
                      <Grid item key={index}>
                        <Chip 
                          label={suggestion} 
                          onClick={() => handleSuggestionClick(suggestion)}
                          clickable
                        />
                      </Grid>
                    ))}
                  </Grid>
                </Box>
              ) : (
                <Box>
                  {messages.map((message) => (
                    <Box
                      key={message.id}
                      sx={{
                        display: 'flex',
                        justifyContent: message.role === 'user' ? 'flex-end' : 'flex-start',
                        mb: 2,
                      }}
                    >
                      <Box
                        sx={{
                          maxWidth: '70%',
                          p: 2,
                          borderRadius: 2,
                          bgcolor: message.role === 'user' ? 'primary.main' : 'grey.100',
                          color: message.role === 'user' ? 'white' : 'text.primary',
                        }}
                      >
                        <Typography variant="body1">{message.content}</Typography>
                        <Typography variant="caption" sx={{ opacity: 0.7, display: 'block', textAlign: 'right', mt: 1 }}>
                          {formatTimestamp(message.timestamp)}
                        </Typography>
                      </Box>
                    </Box>
                  ))}
                  <div ref={messagesEndRef} />
                </Box>
              )}
            </Box>

            {/* Input area */}
            <Box sx={{ p: 2, borderTop: 1, borderColor: 'divider' }}>
              {error && (
                <Alert severity="error" sx={{ mb: 2 }}>
                  {error}
                </Alert>
              )}
              <Box display="flex">
                <TextField
                  fullWidth
                  variant="outlined"
                  placeholder="Ask something..."
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyPress={handleKeyPress}
                  disabled={loading}
                  sx={{ mr: 1 }}
                />
                <Button
                  variant="contained"
                  color="primary"
                  endIcon={loading ? <CircularProgress size={20} color="inherit" /> : <Send />}
                  onClick={handleSendMessage}
                  disabled={!query.trim() || loading}
                >
                  {loading ? 'Sending' : 'Send'}
                </Button>
              </Box>
            </Box>
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default NaturalLanguage;
